439	          <KialiIcon.Applications className={topologyStyle} />
440	          {numApps.toString()} {numApps === 1 ? 'app ' : 'apps '}
441	          {numVersions > 0 && `(${numVersions} versions)`}
442	        </div>
443	      )}
444	
445	      {numSvc > 0 && (
