447	          <KialiIcon.Services className={topologyStyle} />
448	          {numSvc.toString()} {numSvc === 1 ? 'service' : 'services'}
449	        </div>
450	      )}
451	
452	      {numWorkloads > 0 && (
453	        <div>
454	          <KialiIcon.Workloads className={topologyStyle} />
455	          {numWorkloads.toString()} {numWorkloads === 1 ? 'workload' : 'workloads'}
456	        </div>
457	      )}
458	
459	      {numEdges > 0 && (
460	        <div>
461	          <KialiIcon.Topology className={topologyStyle} />
462	          {numEdges.toString()} {numEdges === 1 ? 'edge' : 'edges'}
