468	  private renderCharts = (): React.ReactNode => {
469	    const props: SummaryPanelPropType = this.props;
470	    const elem = props.data.summaryTarget as GraphElement;
471	    const namespace = elem.getData()[NodeAttr.namespace];
472	
473	    if (this.state.loading) {
474	      return <strong>Loading chart...</strong>;
475	    } else if (this.state.metricsLoadError) {
476	      return (
477	        <div>
478	          <KialiIcon.Warning /> <strong>Error loading metrics: </strong>
479	          {this.state.metricsLoadError}
480	        </div>
481	      );
482	    } else if (namespace === UNKNOWN) {
483	      return <></>;
484	    }
485	
486	    // When there is any traffic for the protocol, show both inbound and outbound charts. It's a little
487	    // confusing because for the tabs inbound is limited to just traffic entering the namespace, and outbound
488	    // is limited to just traffic exiting the namespace.  But in the charts inbound ad outbound also
489	    // includes traffic within the namespace.
490	    const { grpcTotal, httpTotal, isGrpcRequests, tcpTotal } = this.boxTraffic!;
491	
492	    return (
493	      <>
494	        {grpcTotal.rate > 0 && isGrpcRequests && (
495	          <>
496	            <RequestChart
497	              label="gRPC - Inbound Request Traffic"
498	              dataRps={this.state.grpcRequestIn}
499	              dataErrors={this.state.grpcRequestErrIn}
500	            />
501	
502	            <RequestChart
503	              label="gRPC - Outbound Request Traffic"
504	              dataRps={this.state.grpcRequestOut}
505	              dataErrors={this.state.grpcRequestErrOut}
506	            />
507	          </>
508	        )}
509	
510	        {grpcTotal.rate > 0 && !isGrpcRequests && (
511	          <>
512	            <StreamChart
513	              label="gRPC - Inbound Traffic"
514	              receivedRates={this.state.grpcReceivedIn}
515	              sentRates={this.state.grpcSentIn}
516	              unit="messages"
517	            />
518	
519	            <StreamChart
520	              label="gRPC - Outbound Traffic"
521	              receivedRates={this.state.grpcReceivedOut}
522	              sentRates={this.state.grpcSentOut}
523	              unit="messages"
524	            />
525	          </>
526	        )}
527	
528	        {httpTotal.rate > 0 && (
529	          <>
530	            <RequestChart
531	              label="HTTP - Inbound Request Traffic"
532	              dataRps={this.state.httpRequestIn}
533	              dataErrors={this.state.httpRequestErrIn}
534	            />
535	
536	            <RequestChart
537	              label="HTTP - Outbound Request Traffic"
538	              dataRps={this.state.httpRequestOut}
539	              dataErrors={this.state.httpRequestErrOut}
540	            />
541	          </>
542	        )}
543	
544	        {tcpTotal.rate > 0 && (
545	          <>
546	            <StreamChart
547	              label="TCP - Inbound Traffic"
548	              receivedRates={this.state.tcpReceivedIn}
549	              sentRates={this.state.tcpSentIn}
550	              unit="bytes"
551	            />
552	
553	            <StreamChart
554	              label="TCP - Outbound Traffic"
555	              receivedRates={this.state.tcpReceivedOut}
556	              sentRates={this.state.tcpSentOut}
557	              unit="bytes"
558	            />
559	          </>
560	        )}
561	      </>
562	    );
563	  };
