337	    const data = namespaceBox.getData();
338	    const boxed = descendents(namespaceBox);
339	    const namespace = data[NodeAttr.namespace];
340	    const cluster = data[NodeAttr.cluster];
341	
342	    let inboundEdges: Edge[] | any;
343	    let outboundEdges: Edge[] | any;
344	    let totalEdges: Edge[] | any;
345	
346	    const controller = (namespaceBox as Node).getController();
347	    const { nodes } = elems(controller);
348	
349	    const outsideNodes = selectOr(nodes, [
350	      [{ prop: NodeAttr.namespace, op: '!=', val: namespace }],
351	      [{ prop: NodeAttr.cluster, op: '!=', val: cluster }]
352	    ]) as Node[];
353	
354	    // inbound edges are from a different namespace or a different cluster
355	    inboundEdges = edgesOut(outsideNodes, boxed);
356	
357	    // outbound edges are to a different namespace or a different cluster
358	    outboundEdges = edgesIn(outsideNodes, boxed);
359	
360	    // total edges are inbound + edges from boxed workload|app|root nodes (i.e. not injected service nodes or box nodes)
361	    totalEdges = [...inboundEdges];
362	    totalEdges.push(...edgesOut(select(boxed, { prop: NodeAttr.workload, op: 'truthy' }) as Node[]));
363	
364	    return {
365	      grpcIn: getAccumulatedTrafficRateGrpc(inboundEdges),
366	      grpcOut: getAccumulatedTrafficRateGrpc(outboundEdges),
367	      grpcTotal: getAccumulatedTrafficRateGrpc(totalEdges),
368	      httpIn: getAccumulatedTrafficRateHttp(inboundEdges),
369	      httpOut: getAccumulatedTrafficRateHttp(outboundEdges),
