578	
579	    // When there is any traffic for the protocol, show both inbound and outbound charts. It's a little
580	    // confusing because for the tabs inbound is limited to just traffic entering the namespace, and outbound
581	    // is limited to just traffic exitingt the namespace.  But in the charts inbound ad outbound also
582	    // includes traffic within the namespace.
583	    const { grpcTotal, httpTotal, isGrpcRequests, tcpTotal } = this.boxTraffic!;
584	
585	    if (this.metricsPromise) {
586	      this.metricsPromise.cancel();
587	      this.metricsPromise = undefined;
588	    }
589	
590	    let promiseIn: Promise<ApiResponse<IstioMetricsMap>> = Promise.resolve({ data: {} });
591	    let promiseOut: Promise<ApiResponse<IstioMetricsMap>> = Promise.resolve({ data: {} });
592	
593	    let filters: string[] = [];
594	
595	    if (grpcTotal.rate > 0 && !isGrpcRequests) {
596	      filters.push('grpc_sent', 'grpc_received');
597	    }
598	
599	    if (httpTotal.rate > 0 || (grpcTotal.rate > 0 && isGrpcRequests)) {
600	      filters.push('request_count', 'request_error_count');
601	    }
602	
603	    if (tcpTotal.rate > 0) {
604	      filters.push('tcp_sent', 'tcp_received');
605	    }
606	
607	    if (filters.length > 0) {
608	      promiseIn = API.getNamespaceMetrics(
609	        namespace,
610	        {
611	          byLabels: ['request_protocol'], // ignored by prom if it doesn't exist
612	          direction: 'inbound',
613	          duration: props.duration,
614	          filters: filters,
615	          includeAmbient: serverConfig.ambientEnabled, // TODO change to "nodeData.isAmbient" when it is set for this node type
616	          queryTime: props.queryTime,
617	          rateInterval: props.rateInterval,
618	          reporter: 'destination',
619	          step: props.step
620	        },
621	        cluster
622	      );
623	      promiseOut = API.getNamespaceMetrics(
624	        namespace,
625	        {
626	          byLabels: ['request_protocol'], // ignored by prom if it doesn't exist
627	          direction: 'outbound',
628	          duration: props.duration,
629	          filters: filters,
630	          includeAmbient: serverConfig.ambientEnabled, // TODO change to "nodeData.isAmbient" when it is set for this node type
631	          queryTime: props.queryTime,
632	          rateInterval: props.rateInterval,
633	          reporter: 'source',
634	          step: props.step
635	        },
636	        cluster
637	      );
638	    }
639	
640	    this.metricsPromise = makeCancelablePromise(Promise.all([promiseIn, promiseOut]));
641	
642	    this.metricsPromise.promise
643	      .then(responses => {
644	        const comparator = (labels: Labels, protocol?: Protocol): boolean => {
645	          return protocol ? labels.request_protocol === protocol : true;
646	        };
647	
648	        const metricsIn = responses[0].data;
649	        const metricsOut = responses[1].data;
650	
651	        this.setState({
652	          loading: false,
653	          grpcReceivedIn: getFirstDatapoints(metricsIn.grpc_received),
654	          grpcReceivedOut: getFirstDatapoints(metricsOut.grpc_received),
655	          grpcRequestIn: getDatapoints(metricsIn.request_count, comparator, Protocol.GRPC),
656	          grpcRequestOut: getDatapoints(metricsOut.request_count, comparator, Protocol.GRPC),
657	          grpcRequestErrIn: getDatapoints(metricsIn.request_error_count, comparator, Protocol.GRPC),
658	          grpcRequestErrOut: getDatapoints(metricsOut.request_error_count, comparator, Protocol.GRPC),
659	          grpcSentIn: getFirstDatapoints(metricsIn.grpc_sent),
660	          grpcSentOut: getFirstDatapoints(metricsOut.grpc_sent),
661	          httpRequestIn: getDatapoints(metricsIn.request_count, comparator, Protocol.HTTP),
662	          httpRequestOut: getDatapoints(metricsOut.request_count, comparator, Protocol.HTTP),
663	          httpRequestErrIn: getDatapoints(metricsIn.request_error_count, comparator, Protocol.HTTP),
664	          httpRequestErrOut: getDatapoints(metricsOut.request_error_count, comparator, Protocol.HTTP),
665	          tcpReceivedIn: getFirstDatapoints(metricsIn.tcp_received),
666	          tcpReceivedOut: getFirstDatapoints(metricsOut.tcp_received),
667	          tcpSentIn: getFirstDatapoints(metricsIn.tcp_sent),
668	          tcpSentOut: getFirstDatapoints(metricsOut.tcp_sent)
669	        });
670	      })
671	      .catch(error => {
672	        if (error.isCanceled) {
673	          console.debug('SummaryPanelNamespaceBox: Ignore fetch error (canceled).');
674	          return;
675	        }
676	
677	        const errorMsg = error.response && error.response.data.error ? error.response.data.error : error.message;
678	
679	        this.setState({
680	          loading: false,
681	          metricsLoadError: errorMsg,
682	          ...defaultMetricsState
683	        });
684	      });
685	
686	    this.setState({ loading: true, metricsLoadError: null });
687	  };
